import { useState, useEffect, useCallback, useRef } from "react";
import { Button } from "@/components/ui/button";
import { Check, Crown, Loader2, Zap, Globe, TrendingUp, Users, ExternalLink, Store, Star, Sparkles } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/contexts/AuthContext";
import { useTranslation } from "react-i18next";
import { useCreateMembershipOrder } from "@/hooks/useMembershipOrders";
import { supabase } from "@/integrations/supabase/client";
import { useProfile } from "@/hooks/useProfile";
import { cn } from "@/lib/utils";
import { Badge } from "@/components/ui/badge";

type VipTier = "vip1" | "vip2" | "vip3";

interface TierConfig {
  id: VipTier;
  productId: string;
  price: number;
  storeCount: number;
  icon: typeof Crown;
  colorClass: string;
  bgClass: string;
  borderClass: string;
  badgeClass: string;
}

const TIERS: TierConfig[] = [
  {
    id: "vip1",
    productId: "VIP1",
    price: 9.99,
    storeCount: 1,
    icon: Crown,
    colorClass: "text-amber-600",
    bgClass: "bg-amber-50 dark:bg-amber-950/30",
    borderClass: "border-amber-200 dark:border-amber-800",
    badgeClass: "bg-amber-100 text-amber-800 dark:bg-amber-900 dark:text-amber-200",
  },
  {
    id: "vip2",
    productId: "VIP2",
    price: 17.99,
    storeCount: 2,
    icon: Star,
    colorClass: "text-violet-600",
    bgClass: "bg-violet-50 dark:bg-violet-950/30",
    borderClass: "border-violet-200 dark:border-violet-800",
    badgeClass: "bg-violet-100 text-violet-800 dark:bg-violet-900 dark:text-violet-200",
  },
  {
    id: "vip3",
    productId: "VIP3",
    price: 24.99,
    storeCount: 3,
    icon: Sparkles,
    colorClass: "text-rose-600",
    bgClass: "bg-rose-50 dark:bg-rose-950/30",
    borderClass: "border-rose-200 dark:border-rose-800",
    badgeClass: "bg-rose-100 text-rose-800 dark:bg-rose-900 dark:text-rose-200",
  },
];

interface ProductPrice {
  id: string;
  price: string;
  displayPrice: string;
  currencyCode: string;
}

const Membership = () => {
  const { toast } = useToast();
  const { user } = useAuth();
  const { t } = useTranslation();
  const { data: profile } = useProfile();
  const [purchasing, setPurchasing] = useState(false);
  const [selectedTier, setSelectedTier] = useState<VipTier>("vip1");
  const [productPrices, setProductPrices] = useState<Record<string, ProductPrice>>({});
  const createOrder = useCreateMembershipOrder();

  // 向原生 App 请求 StoreKit 价格
  useEffect(() => {
    (window as any).onReceiveProducts = (products: ProductPrice[]) => {
      const map: Record<string, ProductPrice> = {};
      (products || []).forEach(p => { map[p.id] = p; });
      setProductPrices(map);
    };

    try {
      const webkit = (window as any).webkit;
      if (webkit?.messageHandlers?.VoiceBridge) {
        const ids = TIERS.map(t => t.productId).join(",");
        webkit.messageHandlers.VoiceBridge.postMessage(`getProducts:${ids}`);
      }
    } catch (e) {
      console.log("Not in native app, using default prices");
    }

    return () => { delete (window as any).onReceiveProducts; };
  }, []);

  const currentVip = profile?.vip_level as VipTier | null;
  const vipExpiresAt = profile?.vip_expires_at as string | null;
  const isActive = currentVip && vipExpiresAt && new Date(vipExpiresAt) > new Date();

  const tierLabels: Record<VipTier, string> = {
    vip1: t("membership.vip1", "普通会员"),
    vip2: t("membership.vip2", "高级会员"),
    vip3: t("membership.vip3", "超级会员"),
  };

  const handlePurchaseResult = useCallback(async (msg: string, transactionId?: string) => {
    setPurchasing(false);
    const msgStr = String(msg);
    let status = "failed";
    if (msgStr === "success") status = "success";
    else if (msgStr === "userCancelled") status = "cancelled";
    else if (msgStr === "pending") status = "pending";

    const tier = TIERS.find(t => t.id === selectedTier)!;
    try {
      await createOrder.mutateAsync({
        product_id: tier.productId,
        status,
        apple_transaction_id: transactionId || undefined,
        amount: tier.price,
        currency: "USD",
        platform: "ios",
        error_message: status === "failed" ? msgStr : undefined,
      });
    } catch (e) {
      console.error("Failed to save order:", e);
    }

    if (msgStr === "success") {
      toast({ title: t("membership.toast.success"), description: t("membership.toast.successDesc") });
    } else if (msgStr === "userCancelled") {
      toast({ title: t("membership.toast.cancelled"), description: t("membership.toast.cancelledDesc") });
    } else if (msgStr === "pending") {
      toast({ title: t("membership.toast.pending"), description: t("membership.toast.pendingDesc") });
    } else {
      toast({ title: t("membership.toast.failed"), description: `${t("membership.toast.error")}: ${msgStr}`, variant: "destructive" });
    }
  }, [toast, t, createOrder, selectedTier]);

  useEffect(() => {
    (window as any).onReceivePurchase = (msg: any, transactionId?: any) => {
      handlePurchaseResult(String(msg), transactionId ? String(transactionId) : undefined);
    };
    return () => { delete (window as any).onReceivePurchase; };
  }, [handlePurchaseResult]);

  const handlePurchase = (tierId: VipTier) => {
    if (!user) {
      toast({ title: t("membership.toast.loginRequired"), description: t("membership.toast.loginRequiredDesc"), variant: "destructive" });
      return;
    }
    setSelectedTier(tierId);
    setPurchasing(true);
    const tier = TIERS.find(t => t.id === tierId)!;
    try {
      const webkit = (window as any).webkit;
      if (webkit?.messageHandlers?.VoiceBridge) {
        webkit.messageHandlers.VoiceBridge.postMessage(`purchase:${tier.productId}`);
      } else {
        setPurchasing(false);
        toast({ title: t("membership.toast.notice"), description: t("membership.toast.purchaseInApp"), variant: "destructive" });
      }
    } catch {
      setPurchasing(false);
      toast({ title: t("membership.toast.error"), description: t("membership.toast.connectionError"), variant: "destructive" });
    }
  };

  return (
    <div className="min-h-screen bg-background pb-24">
      <div className="px-4 pt-8 pb-6 max-w-lg mx-auto space-y-6">
        {/* Hero */}
        <div className="text-center space-y-3">
          <div className="inline-flex items-center justify-center h-14 w-14 rounded-2xl bg-gradient-to-br from-primary/20 to-primary/5 border border-primary/20">
            <Crown className="h-7 w-7 text-primary" />
          </div>
          <h1 className="text-2xl font-bold">{t("membership.title", "VIP 会员")}</h1>
          <p className="text-sm text-muted-foreground leading-relaxed">
            {t("membership.subtitle", "解锁商店流量接口，让您的餐厅触达更多顾客")}
          </p>
        </div>

        {/* Current VIP status */}
        {isActive && currentVip && (
          <div className={cn(
            "rounded-xl border p-4 flex items-center gap-3",
            TIERS.find(t => t.id === currentVip)?.bgClass,
            TIERS.find(t => t.id === currentVip)?.borderClass,
          )}>
            <Crown className={cn("h-5 w-5", TIERS.find(t => t.id === currentVip)?.colorClass)} />
            <div className="flex-1">
              <p className="text-sm font-semibold">{t("membership.currentPlan", "当前套餐")}: {tierLabels[currentVip]}</p>
              <p className="text-xs text-muted-foreground">
                {t("membership.expiresAt", "到期时间")}: {new Date(vipExpiresAt!).toLocaleDateString()}
              </p>
            </div>
          </div>
        )}

        {/* Tier cards */}
        <div className="space-y-3">
          {TIERS.map((tier) => {
            const TierIcon = tier.icon;
            const isCurrent = isActive && currentVip === tier.id;
            return (
              <div
                key={tier.id}
                className={cn(
                  "rounded-xl border-2 p-5 transition-all relative",
                  isCurrent ? `${tier.borderClass} ${tier.bgClass}` : "border-border hover:border-primary/30",
                )}
              >
                {/* Popular badge for VIP2 */}
                {tier.id === "vip2" && (
                  <Badge className="absolute -top-2.5 right-4 bg-primary text-primary-foreground text-[10px] px-2">
                    {t("membership.popular", "最受欢迎")}
                  </Badge>
                )}

                <div className="flex items-start gap-4">
                  <div className={cn(
                    "h-11 w-11 rounded-xl flex items-center justify-center shrink-0",
                    tier.bgClass,
                  )}>
                    <TierIcon className={cn("h-5 w-5", tier.colorClass)} />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-semibold text-base">{tierLabels[tier.id]}</h3>
                      <Badge variant="outline" className={cn("text-[10px]", tier.badgeClass)}>
                        {tier.id.toUpperCase()}
                      </Badge>
                    </div>
                    
                    <div className="flex items-center gap-1 mb-3">
                      <Store className="h-3.5 w-3.5 text-muted-foreground" />
                      <span className="text-xs text-muted-foreground">
                        {t("membership.storeQuota", "可管理 {{count}} 个带流量接口的商店", { count: tier.storeCount })}
                      </span>
                    </div>

                    <div className="flex items-end justify-between">
                      <div>
                        <span className="text-2xl font-extrabold">
                          {productPrices[tier.productId]?.displayPrice ?? `$${tier.price}`}
                        </span>
                        <span className="text-xs text-muted-foreground ml-1">/{t("membership.perMonth", "月")}</span>
                      </div>
                      <Button
                        size="sm"
                        onClick={() => handlePurchase(tier.id)}
                        disabled={purchasing || isCurrent}
                        className="h-8 px-4 text-xs"
                        variant={isCurrent ? "outline" : "default"}
                      >
                        {purchasing && selectedTier === tier.id ? (
                          <Loader2 className="h-3 w-3 animate-spin" />
                        ) : isCurrent ? (
                          t("membership.currentPlan", "当前套餐")
                        ) : currentVip && isActive ? (
                          t("membership.upgrade", "升级")
                        ) : (
                          t("membership.subscribe", "立即订阅")
                        )}
                      </Button>
                    </div>
                  </div>
                </div>

                {/* Features list */}
                <div className="mt-3 pt-3 border-t border-border/50 space-y-1.5">
                  <div className="flex items-center gap-2">
                    <Check className="h-3.5 w-3.5 text-primary shrink-0" />
                    <span className="text-xs">{t("membership.feature.apiAccess", "商店 API 接口访问权限")}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Check className="h-3.5 w-3.5 text-primary shrink-0" />
                    <span className="text-xs">{t("membership.feature.storeManagement", "商店管理与数据分析")}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Check className="h-3.5 w-3.5 text-primary shrink-0" />
                    <span className="text-xs">
                      {tier.storeCount === 1
                        ? t("membership.feature.oneStore", "管理 1 个商店")
                        : t("membership.feature.multiStore", "管理最多 {{count}} 个商店", { count: tier.storeCount })}
                    </span>
                  </div>
                  {tier.id !== "vip1" && (
                    <div className="flex items-center gap-2">
                      <Check className="h-3.5 w-3.5 text-primary shrink-0" />
                      <span className="text-xs">{t("membership.feature.prioritySupport", "优先客服支持")}</span>
                    </div>
                  )}
                  {tier.id === "vip3" && (
                    <div className="flex items-center gap-2">
                      <Check className="h-3.5 w-3.5 text-primary shrink-0" />
                      <span className="text-xs">{t("membership.feature.exclusiveBadge", "专属超级会员徽章")}</span>
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>

        {/* What is API Traffic */}
        <div className="rounded-xl border bg-card p-5 space-y-3">
          <div className="flex items-center gap-2">
            <Zap className="h-5 w-5 text-primary" />
            <h2 className="font-semibold text-base">{t("membership.whatIsTrafficPool", "什么是流量接口？")}</h2>
          </div>
          <p className="text-sm text-muted-foreground leading-relaxed">
            {t("membership.trafficPoolDesc", "流量接口让您的商店可以对接外部平台（如外卖平台、预订系统等），通过 API 实现自动化运营，提升曝光和订单量。")}
          </p>
        </div>

        {/* Footer */}
        <div className="text-center space-y-1 text-[11px] text-muted-foreground">
          <p>{t("membership.autoRenewNote", "订阅将自动续费，可随时取消")}</p>
          <p>
            {t("membership.agreeToTerms", "订阅即表示同意")}{" "}
            <a href="/terms-of-service" className="underline text-primary">{t("membership.termsOfService", "服务条款")}</a>
            {" & "}
            <a href="/privacy-policy" className="underline text-primary">{t("membership.privacyPolicy", "隐私政策")}</a>
          </p>
        </div>
      </div>
    </div>
  );
};

export default Membership;
